with:
  # Build a list of clause strings directly from each triple, preserving input order
      clauses: list[str] = []
      for t in triples:
          formatter = templates.get(t.predicate)
          if formatter:
              clause = formatter(t.subject, t.object)
          else:
              clause = f"{t.subject} {t.predicate} {t.object}"
          clauses.append(clause)

      # Combine clauses into a single fluent sentence
      if not clauses:
          return ""
      if len(clauses) == 1:
          sentence_body = clauses[0]
      else:
          sentence_body = ", ".join(clauses[:-1]) + ", and " + clauses[-1]

      # Ensure the sentence ends with a period
      sentence = sentence_body.strip()
      if not sentence.endswith('.'):
          sentence += '.'
      return sentence
